import React from "react";
import { useNavigate } from "react-router-dom";
import "../styles/Dashboard.css";

import {
  MessageCircle,
  Smile,
  Moon,
  AlertTriangle,
  Clock,
  LogOut,
} from "lucide-react";

function Dashboard() {
  const navigate = useNavigate();

  return (
    <div className="dashboard-wrapper">
      <h1 className="dashboard-title">Dashboard Loaded ✅</h1>
      <p className="dashboard-subtitle">
        Welcome to your Mental Health Assistant
      </p>

      <div className="dashboard-grid">

        {/* General Chat */}
        <div
          className="dashboard-card"
          onClick={() => navigate("/chat")}
          style={{ cursor: "pointer" }}
        >
          <MessageCircle size={36} />
          <h3>General Chat</h3>
          <p>Talk freely with your AI therapist</p>
        </div>

        {/* Mood Tracker */}
        <div
          className="dashboard-card"
          onClick={() => navigate("/mood-tracker")}
          style={{ cursor: "pointer" }}
        >
          <Smile size={36} />
          <h3>Mood Tracker</h3>
          <p>Track your daily emotions</p>
        </div>

        {/* Sleep Tracker (future) */}
        <div className="dashboard-card">
          <Moon size={36} />
          <h3>Sleep Tracker</h3>
          <p>Understand your sleep patterns</p>
        </div>

        {/* Crisis Support */}
        <div
          className="dashboard-card warning"
          onClick={() => navigate("/crisis")}
          style={{ cursor: "pointer" }}
        >
          <AlertTriangle size={36} />
          <h3>Crisis Support</h3>
          <p>Immediate help when you need it</p>
        </div>

        {/* Chat History */}
        <div className="dashboard-card">
          <Clock size={36} />
          <h3>Chat History</h3>
          <p>Review past conversations</p>
        </div>

        {/* Logout */}
        <div
          className="dashboard-card logout"
          onClick={() => navigate("/")}
          style={{ cursor: "pointer" }}
        >
          <LogOut size={36} />
          <h3>Logout</h3>
          <p>Safely exit your account</p>
        </div>

      </div>
    </div>
  );
}

export default Dashboard;
